import React, { useState } from 'react';
import IndividualAnalysis from './IndividualAnalysis';
import BatchAnalysis from './BatchAnalysis';
import './App.css';
import logo from './assets/images/logo.png';

function App() {
  const [customerData, setCustomerData] = useState({});
  const [results, setResults] = useState(null);
  const [loading, setLoading] = useState(false);

  const [selectedFile, setSelectedFile] = useState(null);
  const [batchResults, setBatchResults] = useState(null);
  const [batchLoading, setBatchLoading] = useState(false);

  const [currentView, setCurrentView] = useState('individual');
  const [sidebarOpen, setSidebarOpen] = useState(false);

  const handleInputChange = (newData) => {
    setCustomerData(newData);
  };

  const handleAnalyze = async () => {
    setLoading(true);
    try {
      const response = await fetch('http://localhost:5000/api/analyze-single', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ customer_data: customerData }),
      });

      if (!response.ok) {
        throw new Error('Analysis failed');
      }

      const data = await response.json();
      setResults(data);
    } catch (error) {
      console.error('Error analyzing customer:', error);
      // Fallback to simulated results if API fails
      const simulatedResults = {
        probability: Math.random() * 0.7 + 0.3,
        prediction: Math.random() > 0.5,
        feature_importance: {
          Tenure: 0.3,
          SatisfactionScore: 0.25,
          OrderCount: 0.2,
          CashbackAmount: 0.15,
          DaySinceLastOrder: 0.1
        },
        business_impact: {
          estimated_clv: 15000,
          retention_budget: 2250,
          potential_revenue_loss: 4500,
          roi_retention: 2.0
        }
      };
      setResults(simulatedResults);
    } finally {
      setLoading(false);
    }
  };

  const handleReset = () => {
    setCustomerData({});
    setResults(null);
  };

  const handleFileChange = (e) => {
    const file = e.target.files[0];
    setSelectedFile(file);
  };

  const handleBatchAnalyze = async () => {
    if (!selectedFile) return;

    setBatchLoading(true);
    try {
      const formData = new FormData();
      formData.append('file', selectedFile);

      const response = await fetch('http://localhost:5000/api/analyze-batch', {
        method: 'POST',
        body: formData,
      });

      if (!response.ok) {
        throw new Error('Batch analysis failed');
      }

      const data = await response.json();
      setBatchResults(data);
    } catch (error) {
      console.error('Error analyzing batch:', error);
      // Fallback to simulated results
      const simulatedBatchResults = {
        summary: {
          total_customers: 1500,
          high_risk_count: 345,
          high_risk_percentage: 23.0,
          total_potential_loss: 287500,
          roi_retention: 3.2
        },
        risk_distribution: {
          'P1: High Risk (>70%)': 345,
          'P2: Moderate Risk (31-70%)': 600,
          'P3: Low Risk (<=30%)': 555
        },
        data: Array.from({ length: 50 }, (_, i) => ({
          id: i + 1,
          Tenure: Math.floor(Math.random() * 24) + 1,
          OrderCount: Math.floor(Math.random() * 20) + 1,
          CashbackAmount: Math.floor(Math.random() * 20000) + 1000,
          DaySinceLastOrder: Math.floor(Math.random() * 60) + 1,
          SatisfactionScore: Math.floor(Math.random() * 5) + 1,
          Churn_Probability: Math.random() * 0.8 + 0.1,
          Risk_Level: ['P1: High Risk (>70%)', 'P2: Moderate Risk (31-70%)', 'P3: Low Risk (<=30%)'][Math.floor(Math.random() * 3)]
        }))
      };
      setBatchResults(simulatedBatchResults);
    } finally {
      setBatchLoading(false);
    }
  };

  const toggleSidebar = () => {
    setSidebarOpen(!sidebarOpen);
  };

  return (
    <div className="app">
      {/* Header */}
      <div className="app-header">
        <div className="header-left">
          <div className="logo-title-container">
            <div className="app-logo">
              <img src={logo} alt="PREDICTIVE CHURNWISE ANALYTICS" className="logo-image" />
            </div>
            <div className="title-container">
              <h1 className="app-title">Executive Churn Intelligence Platform</h1>
              <div className="session-title">Unified predictive insights — action-first, financialized, and presentation-ready</div>
            </div>
          </div>
        </div>
        <div className="header-right">
          <div className="header-stats">
            <div className="stat-item">
              <span className="stat-label">Model Accuracy</span>
              <span className="stat-value">92%</span>
            </div>
            <div className="stat-item">
              <span className="stat-label">Last Updated</span>
              <span className="stat-value">{new Date().toLocaleTimeString()}</span>
            </div>
          </div>
        </div>
      </div>

      <div className="main-layout">
        {/* Sidebar */}
        <div className={`sidebar ${sidebarOpen ? 'open' : 'closed'}`}>
          <nav className="sidebar-nav">
            <div className="nav-toggle-section">
              <button 
                className="nav-toggle-btn"
                onClick={toggleSidebar}
              >
                <span className="nav-toggle-icon">
                  {sidebarOpen ? '◀' : '▶'}
                </span>
                {sidebarOpen && <span className="nav-toggle-text">Collapse</span>}
              </button>
            </div>

            <button 
              className={`nav-item ${currentView === 'individual' ? 'active' : ''}`}
              onClick={() => setCurrentView('individual')}
              data-tooltip="Individual Analysis"
            >
              <span className="nav-icon">👤</span>
              {sidebarOpen && <span className="nav-text">Individual Analysis</span>}
            </button>
            <button 
              className={`nav-item ${currentView === 'batch' ? 'active' : ''}`}
              onClick={() => setCurrentView('batch')}
              data-tooltip="Batch Processing"
            >
              <span className="nav-icon">⚡</span>
              {sidebarOpen && <span className="nav-text">Batch Processing</span>}
            </button>
          </nav>
        </div>

        {/* Main Content */}
        <div className={`content-area ${!sidebarOpen ? 'expanded' : ''}`}>
          {currentView === 'individual' ? (
            <IndividualAnalysis
              customerData={customerData}
              onInputChange={handleInputChange}
              onAnalyze={handleAnalyze}
              onReset={handleReset}
              loading={loading}
              results={results}
            />
          ) : (
            <BatchAnalysis
              onFileChange={handleFileChange}
              onAnalyze={handleBatchAnalyze}
              loading={batchLoading}
              results={batchResults}
              selectedFile={selectedFile}
            />
          )}
        </div>
      </div>
    </div>
  );
}

export default App;
